const types=[{type:'tip',prompt:'Write a helpful Facebook/Instagram post for Tampa Bay homeowners about hurricane window preparation. 3-4 sentences. Conversational. End with soft CTA to comment.'},{type:'savings',prompt:'Write a post for Tampa Bay homeowners about energy efficient windows lowering electric bills. Mention 15-30% savings. Include a question.'},{type:'seasonal',prompt:'Write a timely post for Tampa Bay homeowners about preparing windows for hurricane season. Practical tips. 3-4 sentences.'},{type:'faq',prompt:'Write a post answering a common Tampa Bay homeowner question about window replacement cost, permits, timeline, or insurance discounts.'},{type:'social_proof',prompt:'Write a post in voice of a satisfied Tampa Bay homeowner who got new windows. First person, authentic, specific benefit. 3-4 sentences.'}];
const tags=['#TampaBay #HomeImprovement #Windows','#Tampa #HurricanePrep #FloridaHome','#StPete #HomeUpgrade #EnergyEfficient','#TampaBayArea #WindowReplacement #FloridaLiving'];
const t=types[new Date().getDay()%types.length];
const tag=tags[Math.floor(Math.random()*tags.length)];
return [{json:{...t,hashtags:tag,date:new Date().toLocaleDateString()}}];

const r=$input.first().json;
const m=$('Pick Post Type').first().json;
const text=r.choices[0].message.content.trim();
const post=`${text}\n\n${m.hashtags}`;
return [{json:{type:m.type,date:m.date,post,char_count:post.length}}];
